# Primitive shape implementations - cross-module inheritance

from shapes import Shape, Point, ShapeType, IDrawable, IResizable

class Rectangle(Shape, IDrawable, IResizable):
    width: float
    height: float
    top_left: Point

    def __init__(self, name: str, w: float, h: float, x: float, y: float):
        super().__init__(name, ShapeType.RECTANGLE)
        self.width = w
        self.height = h
        self.top_left = Point(x, y)

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        x_str: str = str(self.top_left.x)
        y_str: str = str(self.top_left.y)
        return f"Rect[{self.name}]: {self.width}x{self.height}@({x_str},{y_str})"

    @override
    def resize(self, scale: float) -> None:
        self.width = self.width * scale
        self.height = self.height * scale

class Circle(Shape, IDrawable):
    center: Point
    radius: float

    def __init__(self, name: str, cx: float, cy: float, r: float):
        super().__init__(name, ShapeType.CIRCLE)
        self.center = Point(cx, cy)
        self.radius = r

    @override
    def area(self) -> float:
        return 3.141592653589793 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.141592653589793 * self.radius

    @override
    def draw(self) -> str:
        cx_str: str = str(self.center.x)
        cy_str: str = str(self.center.y)
        r_str: str = str(self.radius)
        return f"Circle[{self.name}]: r={r_str}@({cx_str},{cy_str})"

class Square(Rectangle):
    def __init__(self, name: str, side: float, x: float, y: float):
        super().__init__(name, side, side, x, y)

    @override
    def describe(self) -> str:
        w_str: str = str(self.width)
        return f"Square '{self.name}' with side {w_str}"

