# Rendering and composition module

from shapes import Shape, IMeasurable, IDrawable, ShapeType, Point
from primitives import Rectangle, Circle

class Canvas:
    shapes: list[Shape]
    name: str

    def __init__(self, name: str):
        self.name = name
        self.shapes = []

    def add_shape(self, s: Shape) -> None:
        self.shapes.append(s)

    def total_area(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            if isinstance(s, IMeasurable):
                total = total + s.area()
        return total

    def render_all(self) -> list[str]:
        result: list[str] = []
        for s in self.shapes:
            if isinstance(s, IDrawable):
                result.append(s.draw())
            else:
                result.append(f"Non-drawable: {s.name}")
        return result

class BoundingBoxCalculator:
    @staticmethod
    def from_rectangle(rect: Rectangle) -> tuple[float, float, float, float]:
        min_x: float = rect.top_left.x
        min_y: float = rect.top_left.y
        max_x: float = min_x + rect.width
        max_y: float = min_y + rect.height
        return (min_x, min_y, max_x, max_y)

    @staticmethod
    def from_circle(circ: Circle) -> tuple[float, float, float, float]:
        min_x: float = circ.center.x - circ.radius
        min_y: float = circ.center.y - circ.radius
        max_x: float = circ.center.x + circ.radius
        max_y: float = circ.center.y + circ.radius
        return (min_x, min_y, max_x, max_y)
